const msg = $('Telegram Trigger').first().json.message;
const chatId = String(msg.chat.id);
const userId = String(msg.from.id);
const source = 'telegram';
const sessionId = 'telegram:' + chatId;
const qualifiedUserId = 'telegram:' + userId;

function out(userMessage) {
  return [{ json: { userMessage, chatId, userId, sessionId, qualifiedUserId, source } }];
}

let userMessage = '';

// Check voice transcription result
try {
  const transcript = $('Transcribe Voice').first()?.json?.text;
  if (transcript) {
    return out('[Voice message] ' + transcript);
  }
} catch(e) {}

// Try to get file_ref from File Bridge upload
let fileRef = '';
try { fileRef = $('Save File Metadata').first()?.json?.file_ref || ''; } catch(e) {}

// Check photo (analyzed by OpenAI Vision)
try {
  const analysis = $('Analyze Photo').first();
  if (analysis) {
    let description = '';
    const j = analysis.json;
    if (Array.isArray(j)) {
      description = j[0]?.content?.[0]?.text || JSON.stringify(j);
    } else {
      description = j.text || j.content || JSON.stringify(j);
    }
    const caption = msg.caption || '';
    const refTag = fileRef ? ' | file_ref: ' + fileRef : '';
    userMessage = '[Photo' + refTag + ']\n' + description + (caption ? '\n\nUser caption: ' + caption : '');
    return out(userMessage);
  }
} catch(e) {}

// Check document (PDF text extracted by Extract PDF Text node)
try {
  const extracted = $('Extract PDF Text').first();
  if (extracted) {
    const filename = msg.document?.file_name || 'unknown';
    const pdfText = extracted.json.text || '';
    const refTag = fileRef ? ' | file_ref: ' + fileRef : '';
    userMessage = '[Document: ' + filename + refTag + ']\n\n' + pdfText + '\n\n' + (msg.caption || 'Please analyze this document.');
    return out(userMessage);
  }
} catch(e) {}

// Check location
try {
  const locMsg = $('Format Location').first()?.json?.userMessage;
  if (locMsg) {
    return out(locMsg);
  }
} catch(e) {}

// Check unsupported
try {
  const unsup = $('Unsupported Media').first()?.json?.userMessage;
  if (unsup) {
    return out(unsup);
  }
} catch(e) {}

// Default: text message
userMessage = msg.text || '';
return out(userMessage);

const raw = $input.first().json;
const message = raw.message || '';
const chatId = String(raw.chat_id || '');
// Strip 'telegram:' prefix if present to get raw numeric ID
const userId = String(raw.user_id || '').replace('telegram:', '');
const source = raw.source || 'scheduled_task';
const sessionId = 'telegram:' + chatId;
const qualifiedUserId = 'telegram:' + userId;

return [{ json: { userMessage: message, chatId, userId, sessionId, qualifiedUserId, source } }];

// Build system prompt from loaded context
const soul = $('Load Soul').all().map(i => i.json);
// Deduplicate: sequential node chaining causes cartesian product (6 soul × 6 agents = 36 items)
const agentsRaw = $('Load Agents Config').all().map(i => i.json);
const agents = [...new Map(agentsRaw.map(a => [a.key, a])).values()];
const user = $('Load User Profile').first()?.json || {};
// Deduplicate conversation history (36x duplicated due to upstream cartesian product)
const historyRaw = $('Load Conversation History').all().map(i => i.json);
const seenHist = new Set();
const history = historyRaw.filter(h => { const k = h.role + ':' + h.content; if (seenHist.has(k)) return false; seenHist.add(k); return true; });
const mergeData = $('Merge Input').first().json;
const userMessage = mergeData.userMessage || '';
const chatId = mergeData.chatId;
const userId = mergeData.userId;
const inputSource = mergeData.source || 'telegram';

// Build dynamic MCP server list from mcp_registry
const mcpRaw = $('Load MCP Servers').all().map(i => i.json);
const seenMcp = new Set();
const mcpServers = mcpRaw.filter(s => { if (!s.server_name || seenMcp.has(s.server_name)) return false; seenMcp.add(s.server_name); return true; });
let mcpServerList = '';
if (mcpServers.length > 0) {
  mcpServerList = '\n\n## Available MCP Skills:\n' + mcpServers.map(s => {
    const tools = Array.isArray(s.tools) ? s.tools.join(', ') : s.tools;
    return `- ${s.server_name}: ${s.mcp_url} (tools: ${tools})${s.description ? ' — ' + s.description : ''}`;
  }).join('\n');
}

// Inject dynamic server list into mcp_instructions (replace any static server section)
const agentText = agents.map(a => {
  if (a.key === 'mcp_instructions') {
    const cleaned = a.content.replace(/\n## (?:Available MCP (?:Servers|Skills)|Currently installed MCP Skills)[\s\S]*?(?=\n## |$)/, '');
    return `## ${a.key}\n${cleaned}${mcpServerList}`;
  }
  return `## ${a.key}\n${a.content}`;
}).join('\n\n');

// Build soul text
const soulText = soul.map(s => `## ${s.key}\n${s.content}`).join('\n\n');
const userText = user.display_name 
  ? `Name: ${user.display_name} (${user.name})\nTimezone: ${user.timezone}\nKontext: ${user.context}\nPrefs: ${JSON.stringify(user.preferences)}\nSetup done: ${user.setup_done !== false ? 'true' : 'false'}`
  : 'Unbekannter User';

// Build conversation history
const historyText = history.reverse().map(h => `${h.role}: ${h.content}`).join('\n');

// Current date/time in user's timezone
const now = $now.setZone(user.timezone || 'UTC').toFormat('cccc, dd LLLL yyyy, HH:mm');

const scheduledHint = inputSource === 'scheduled_task' ? '\n\n# SCHEDULED TASK\nThis message is a scheduled task that the user set up earlier. Execute the instructions thoroughly and send the result. Start your response with a brief ⏰ note that this is a scheduled task result.' : '';

// Build active projects list (names only — content loaded on demand via Project Manager tool)
const projectsRaw = $('Load Active Projects').all().map(i => i.json);
const seenProj = new Set();
const activeProjects = projectsRaw.filter(p => { if (!p.name || seenProj.has(p.name)) return false; seenProj.add(p.name); return true; });
let projectsSection = '';
if (activeProjects.length > 0) {
  projectsSection = '\n\n# ACTIVE PROJECTS\n' + activeProjects.map(p => {
    const d = p.updated_at ? new Date(p.updated_at).toISOString().split('T')[0] : '';
    return `- ${p.name} (updated: ${d})`;
  }).join('\n') + '\nUse the Project Manager tool to read or update project details.';
}

const systemPrompt = `# CURRENT TIME\n${now}\n\n# SOUL\n${soulText}\n\n# AGENT CONFIG\n${agentText}\n\n# USER PROFILE\n${userText}${scheduledHint}${projectsSection}\n\n# RECENT CONVERSATION\n${historyText}`;

return [{
  json: {
    systemPrompt,
    userMessage,
    chatId: String(chatId),
    userId: String(userId),
    sessionId: mergeData.sessionId || `telegram:${chatId}`,
    qualifiedUserId: mergeData.qualifiedUserId || `telegram:${userId}`,
    source: inputSource,
    _webhookSource: mergeData._webhookSource || false,
    metadata: mergeData.metadata || {}
  }
}];

// Save conversation to Supabase
const bsp = $('Build System Prompt').first().json;
const userMessage = bsp.userMessage;
const assistantMessage = $('AI Agent').first().json.output;
const sessionId = bsp.sessionId;
const userId = bsp.userId;
const qualifiedUserId = bsp.qualifiedUserId;
const source = bsp.source || 'telegram';
