// Mark onboarding as done after first response
const setupDone = $('Load User Profile').first()?.json?.setup_done;
const markSetupDone = setupDone === false;

// Escape $ followed by digits — pg-promise interprets $N as parameter placeholders
function pgSafe(s) { return (s || '').replace(/\$/g, () => '$$'); }

return [{
  json: {
    userMessage: pgSafe(userMessage),
