let text = $('AI Agent').first().json.output || '';

// Strip [send_file: URL] markers (handled by file delivery pipeline)
text = text.replace(/\[send_file:\s*https?:\/\/[^\]]+\]/g, '').trim();

const MAX = 4000;

function sanitizeTelegramMarkdown(t) {
  const codeBlockCount = (t.match(/```/g) || []).length;
  if (codeBlockCount % 2 !== 0) t += '\n```';
  const boldCount = (t.match(/\*\*/g) || []).length;
  if (boldCount % 2 !== 0) {
    const lastIdx = t.lastIndexOf('**');
    t = t.substring(0, lastIdx) + t.substring(lastIdx + 2);
  }
  let singleStarPositions = [];
  for (let i = 0; i < t.length; i++) {
    if (t[i] === '*' && (i === 0 || t[i-1] !== '*') && (i === t.length-1 || t[i+1] !== '*')) singleStarPositions.push(i);
  }
  if (singleStarPositions.length % 2 !== 0 && singleStarPositions.length > 0) {
    const removeIdx = singleStarPositions[singleStarPositions.length - 1];
    t = t.substring(0, removeIdx) + t.substring(removeIdx + 1);
  }
  let underscorePositions = [];
  for (let i = 0; i < t.length; i++) {
    if (t[i] === '_') {
      const context = t.substring(Math.max(0, i - 50), i);
      if (!context.match(/https?:\/\/[^\s]*$/)) underscorePositions.push(i);
    }
  }
  if (underscorePositions.length % 2 !== 0 && underscorePositions.length > 0) {
    const removeIdx = underscorePositions[underscorePositions.length - 1];
    t = t.substring(0, removeIdx) + t.substring(removeIdx + 1);
  }
  let backtickPositions = [];
  for (let i = 0; i < t.length; i++) {
    if (t[i] === '`' && (i === 0 || t[i-1] !== '`') && (i === t.length-1 || t[i+1] !== '`')) backtickPositions.push(i);
  }
  if (backtickPositions.length % 2 !== 0 && backtickPositions.length > 0) {
    const removeIdx = backtickPositions[backtickPositions.length - 1];
    t = t.substring(0, removeIdx) + t.substring(removeIdx + 1);
  }
  return t;
}

if (text.length <= MAX) {
  return [{ json: { text: sanitizeTelegramMarkdown(text) } }];
}

const chunks = [];
let remaining = text;

while (remaining.length > MAX) {
  let cutPoint = remaining.lastIndexOf('\n\n', MAX);
  if (cutPoint < MAX * 0.3) cutPoint = remaining.lastIndexOf('\n', MAX);
  if (cutPoint < MAX * 0.3) cutPoint = remaining.lastIndexOf(' ', MAX);
  if (cutPoint < MAX * 0.3) cutPoint = MAX;
  chunks.push(remaining.substring(0, cutPoint).trim());
  remaining = remaining.substring(cutPoint).trim();
}
if (remaining) chunks.push(remaining);

return chunks.map(c => ({ json: { text: sanitizeTelegramMarkdown(c) } }));

// Load embedding config from DB and generate embedding
async function getEmbedding(text) {
  const cfgResp = await helpers.httpRequest({ method: 'GET', url: '{{SUPABASE_URL}}/rest/v1/tools_config?tool_name=eq.embedding&select=config,enabled', headers: { 'apikey': '{{SUPABASE_SERVICE_KEY}}', 'Content-Type': 'application/json' } });
  const cfg = (Array.isArray(cfgResp) && cfgResp.length > 0 && cfgResp[0].enabled) ? cfgResp[0].config : null;
  if (!cfg || !cfg.api_key) return null;
  const provider = cfg.provider || 'openai';
  const apiKey = cfg.api_key;
  const model = cfg.model || 'text-embedding-3-small';
  try {
    if (provider === 'openai') {
      const res = await helpers.httpRequest({ method: 'POST', url: 'https://api.openai.com/v1/embeddings', headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' }, body: JSON.stringify({ model, input: text }) });
      return res.data[0].embedding;
    }
    if (provider === 'voyage') {
      const res = await helpers.httpRequest({ method: 'POST', url: 'https://api.voyageai.com/v1/embeddings', headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' }, body: JSON.stringify({ model: model || 'voyage-3-lite', input: [text] }) });
      return res.data[0].embedding;
    }
    if (provider === 'ollama') {
      const ollamaUrl = cfg.ollama_url || 'http://localhost:11434';
      const res = await helpers.httpRequest({ method: 'POST', url: `${ollamaUrl}/api/embed`, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ model: model || 'nomic-embed-text', input: text }) });
      return res.embeddings[0];
    }
  } catch(e) { return null; }
  return null;
}

