const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const CHAT_ID = '{{TELEGRAM_CHAT_ID}}';

async function pgrest(method, path, body, extraHeaders = {}) {
  const opts = {
    method,
    url: `${SUPABASE_URL}${path}`,
    headers: { 'apikey': SUPABASE_KEY, 'Content-Type': 'application/json', ...extraHeaders },
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  };
  if (body) opts.body = JSON.stringify(body);
  const res = await helpers.httpRequest(opts);
  if (!res.body || res.body === '') return null;
  return typeof res.body === 'string' ? JSON.parse(res.body) : res.body;
}

let input;
try { input = JSON.parse(query); } catch(e) { return 'Error: invalid JSON. Expected: {"action":"list|create|update|delete|summary|set_preference", ...}'; }

const userId = `telegram:${CHAT_ID}`;
const action = input.action;

if (action === 'list') {
  let filter = `user_id=eq.${encodeURIComponent(userId)}`;
  if (input.status) filter += `&status=eq.${input.status}`;
  if (input.priority) filter += `&priority=eq.${input.priority}`;
  if (input.due_before) filter += `&due_date=lte.${input.due_before}`;
  filter += '&parent_id=is.null&order=due_date.asc.nullslast,priority.desc,created_at.desc';
  const tasks = await pgrest('GET', `/rest/v1/tasks?${filter}&select=*`);
  return JSON.stringify(tasks);

} else if (action === 'create') {
  if (!input.title) return 'Error: title is required';
  const body = {
    user_id: userId,
    title: input.title,
    description: input.description || null,
    priority: input.priority || 'medium',
    due_date: input.due_date || null,
    parent_id: input.parent_id || null,
    tags: input.tags || []
  };
  const result = await pgrest('POST', '/rest/v1/tasks', body, { 'Prefer': 'return=representation' });
  return JSON.stringify({ success: true, task: Array.isArray(result) ? result[0] : result });

} else if (action === 'update') {
  if (!input.id) return 'Error: id is required';
  const body = {};
  if (input.title) body.title = input.title;
  if (input.description !== undefined) body.description = input.description;
  if (input.status) {
    body.status = input.status;
    if (input.status === 'done') body.completed_at = new Date().toISOString();
  }
  if (input.priority) body.priority = input.priority;
  if (input.due_date !== undefined) body.due_date = input.due_date;
  if (input.tags) body.tags = input.tags;
  body.updated_at = new Date().toISOString();
  const result = await pgrest('PATCH', `/rest/v1/tasks?id=eq.${input.id}&user_id=eq.${encodeURIComponent(userId)}`, body, { 'Prefer': 'return=representation' });
  return JSON.stringify({ success: true, task: Array.isArray(result) ? result[0] : result });

} else if (action === 'delete') {
  if (!input.id) return 'Error: id is required';
  await pgrest('DELETE', `/rest/v1/tasks?id=eq.${input.id}&user_id=eq.${encodeURIComponent(userId)}`);
  return JSON.stringify({ success: true, deleted: input.id });

} else if (action === 'summary') {
  const tasks = await pgrest('GET', `/rest/v1/tasks?user_id=eq.${encodeURIComponent(userId)}&status=in.(pending,in_progress)&parent_id=is.null&order=priority.desc,due_date.asc.nullslast&select=*`);
  const profiles = await pgrest('GET', `/rest/v1/user_profiles?user_id=eq.${encodeURIComponent(userId)}&select=timezone`);
  const tz = (profiles && profiles[0] && profiles[0].timezone) || 'Europe/Berlin';
  const now = new Date();
  const todayStr = now.toLocaleDateString('en-CA', { timeZone: tz });
  const overdue = tasks.filter(t => { if (!t.due_date) return false; const d = new Date(t.due_date); return d < now && d.toLocaleDateString('en-CA', { timeZone: tz }) !== todayStr; });
  const dueToday = tasks.filter(t => { if (!t.due_date) return false; return new Date(t.due_date).toLocaleDateString('en-CA', { timeZone: tz }) === todayStr; });
  return JSON.stringify({
    total_pending: tasks.length, overdue: overdue.length, due_today: dueToday.length,
    by_priority: { urgent: tasks.filter(t => t.priority === 'urgent').length, high: tasks.filter(t => t.priority === 'high').length, medium: tasks.filter(t => t.priority === 'medium').length, low: tasks.filter(t => t.priority === 'low').length },
    tasks: tasks.map(t => ({ id: t.id, title: t.title, status: t.status, priority: t.priority, due_date: t.due_date }))
  });

} else if (action === 'set_preference') {
  if (!input.key || input.value === undefined) return 'Error: key and value required';
  const profiles = await pgrest('GET', `/rest/v1/user_profiles?user_id=eq.${encodeURIComponent(userId)}&select=preferences`);
  const current = (profiles[0] && profiles[0].preferences) || {};
  current[input.key] = input.value;
  await pgrest('PATCH', `/rest/v1/user_profiles?user_id=eq.${encodeURIComponent(userId)}`, { preferences: current, updated_at: new Date().toISOString() }, { 'Prefer': 'return=minimal' });
  if (input.key === 'morning_briefing' && input.value.enabled !== undefined) {
    await pgrest('PATCH', `/rest/v1/heartbeat_config?check_name=eq.morning_briefing`, { enabled: input.value.enabled }, { 'Prefer': 'return=minimal' });
  }
  return JSON.stringify({ success: true, preference: input.key, value: input.value });

} else {
  return 'Error: unknown action "' + action + '". Use: list, create, update, delete, summary, set_preference';
}

