const qualifiedUserId = rawUserId.includes(':') ? rawUserId : `api:${rawUserId}`;
const sessionId = rawSessionId
  ? (rawSessionId.includes(':') ? rawSessionId : `${source}:${rawSessionId}`)
  : `${source}:${rawUserId}`;

return [{ json: {
  userMessage: message,
  chatId: null,
  userId: rawUserId,
  sessionId,
  qualifiedUserId,
  source,
  metadata,
  _webhookSource: true
} }];

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const BRIDGE_URL = 'http://file-bridge:3200';

const msg = $('Telegram Trigger').first().json.message;
const sessionId = 'telegram:' + String(msg.chat.id);
const userId = String(msg.from.id);
const upload = $input.first().json;

if (!upload || !upload.id) {
  return [{ json: { file_ref: null } }];
}

await helpers.httpRequest({
  method: 'POST',
  url: SUPABASE_URL + '/rest/v1/file_refs',
  headers: {
    'apikey': SUPABASE_KEY,
    'Authorization': 'Bearer ' + SUPABASE_KEY,
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({
    id: upload.id,
    session_id: sessionId,
    user_id: userId,
    file_name: upload.file_name,
    mime_type: upload.mime_type,
    size_bytes: upload.size_bytes,
    bridge_url: BRIDGE_URL + '/files/' + upload.id
  })
});

return [{ json: { file_ref: upload.id, file_name: upload.file_name } }];

const output = $('AI Agent').first().json.output || '';

// Detect [send_file: URL] pattern
const fileMatch = output.match(/\[send_file:\s*(https?:\/\/[^\]]+)\]/);

let cleanText = output;
let fileUrl = null;
let hasFile = false;

if (fileMatch) {
  fileUrl = fileMatch[1].trim();
  hasFile = true;
  // Remove the marker from the text response
  cleanText = output.replace(fileMatch[0], '').trim();
}

return [{ json: { text: cleanText, fileUrl, hasFile } }];
